var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"어머나. 너무 무섭구나, 시종.","JPN":"僕よ、怖くてたまらないのう。","ENG":"Oh, that is very scary, my servant.","TWN":"唉唷，好恐怖喔，我好怕喔。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"왼쪽 새끼발가락이 저려서 움직일 수도 없겠어.","JPN":"左足の小指がしびれて動けそうにないぞ。","ENG":"My left pinky toe is going numb, I can’t even move.","TWN":"我的左腳小姆指麻了走不動。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런. 하찮은 것이 감히 주인님께 더러운 이빨을 드러내다니, 당장 처리하겠습니다.","JPN":"困りましたね。下賤なモノがご主人様に汚らわしい歯を見せるとは。\\n直ちに始末します。","ENG":"These insignificant ones dare to bare their fangs at my Mistress? I’ll take care of them right away.","TWN":"可惡！這些卑賤的東西，竟然對主人張牙舞爪的，我立刻就去解決他們！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"무슨 소리냐. 그러면 안 되지.","JPN":"何を言っておる？　それはやめよ。","ENG":"No, you shouldn’t.","TWN":"你在胡說八道什麼，這怎麼可以！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 나서면 기껏 여기까지 와서 조난당한 이유가 없지 않느냐.","JPN":"そんなことをしたら、せっかくここまで来て遭難した意味がなくなるではないか。","ENG":"What’s the point of being castaways, if you’ll handle them?","TWN":"你要出手的話，那我們有必要這麼大費周章地來這裡遇難嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"과연! 주인님께서는 항상 계획을 가지고 계시는군요!","JPN":"さすがご主人様！　ご主人様はいつも素晴らしい考えをお持ちですね！","ENG":"I see! You always have a plan, Mistress!","TWN":"主人英明！主人果然無論什麼時候腦袋都很清楚呢！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"제 부족함을 크게 느낍니다. 부디 이 눈이 어두운 자를 꾸짖어 주십시오.","JPN":"どうか愚かなわたくしめに罰を与えてください。","ENG":"I am awed by your greatness. Please chastise my stupidity.","TWN":"我真是望塵莫及！請主人降罪！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"하. 되었다. 너희들을 거둘 때부터 그 정도는 감안했으니까.","JPN":"ふむ、まあよい。僕を引き取る時からそれくらいは予想しておった。","ENG":"Do not worry about it. I knew how you were when I brought you in.","TWN":"哈，算了吧！我在收你們當手下時，早就已經預料到了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"……그나저나 넌 뭐하고 있느냐? 얼른 내 앞에서 사라지지 않고?","JPN":"……ところで其方は何をしておるのじゃ？　早く妾の目の前から消えろ。","ENG":"... By the way, why are you still here? Get out of my sight!","TWN":"……不過你在幹嘛？還不快從我的眼前消失？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응? 나 진짜 돌아가도 돼? 살려 주려고?","JPN":"あれ？　アタシ帰っていいの？　助けてくれるの？","ENG":"Huh? I can go? You’re letting me go?","TWN":"我嗎？我真的可以離開嗎？要放我走？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래. 속고만 살았느냐, 필멸자.","JPN":"左様。定命の者よ、妾は嘘をつかぬ。","ENG":"Yes. Do you have trust issues, mortal?","TWN":"對，難不成你是被騙大的嗎，必滅者？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"으음, 하지만 넌 분명…….","JPN":"うーん、でもアンタさっきは……","ENG":"But you...","TWN":"嗯，可是你明明……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 맡기로 한 조난자 역할은 내가 대신해 주마.","JPN":"其方には遭難者を演じてもらう予定じゃったが、妾がやることにした。","ENG":"I’ll be the castaway instead of you.","TWN":"原本要交給你演的遇難者，換我來演吧～"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네 주인과 그 동맹에 대해서는 아무런 관심도 없다만…….","JPN":"其方の主とその同盟にはなんの興味もないが……","ENG":"I’m not interested in your master, nor her alliance...","TWN":"因為我對你的主人和同盟完全沒興趣……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"곧 이 곳으로 올 존재에 대해서는 조금 흥미가 있거든.","JPN":"まもなくここに来る存在には少し興味があるのじゃ。","ENG":"But I am interested in the being that is currently heading towards here.","TWN":"不過對於等下要來的傢伙倒是有點興趣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러면 할 수 없지, 뭐! 네가 끼어든 건 천재지변 같은 거니까!","JPN":"それじゃあ仕方ないわね！\\nアンタが割り込んで来たのは天変地異のようなものだし！　　","ENG":"Well, there’s nothing I can do! You’re a natural disaster!","TWN":"那好吧，反正事情都被你搞砸啦！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이 뭐라고 하면 레지나에게 일러야지!","JPN":"エデルに文句言われたらレジーナにチクればいいや！","ENG":"If Edel yells at me, I will tell Regina!","TWN":"艾瑟兒如果唸的話，我就要跟蕾佳娜講！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"자아, 그러면 오늘의 주인공을 맞이해 볼까?","JPN":"さあ、それでは今日の主人公を迎え入れるとしようか？","ENG":"Now, let’s go and greet today’s special guest.","TWN":"那就來迎接今天的主角吧～"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 괜찮아?! 그쪽이 조난 신호를 보낸 사람이야?!","JPN":"ちょっと、大丈夫？　あなたが遭難信号を送った人なの！？","ENG":"Hey, are you alright? Are you the one who sent out the distress signal?","TWN":"喂，你還好嗎？！是你發的求救訊號嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아아, 그렇단다! 너무너무 무서워서 이렇게 떨고 있구나!","JPN":"ああ、そうじゃ！　怖すぎて震えが止まらぬ！","ENG":"Oh, yes, truly! I’m so frightened. Look, I’m trembling like a tree in the wind!","TWN":"喔喔，對啊！我超怕的，怕到全身像這樣發抖！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"어서 이 몸을 구해다오!","JPN":"早く妾を助け出しておくれ！","ENG":"Come and save me!","TWN":"快救我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};